    96→## 2. State Management Patterns
    97→
    98→### HYPOTHESIS
    99→The canvas uses `@zazcart/tools` (custom state machine library) instead of React hooks to solve stale closure problems in animation loops.
   100→
   101→### EVIDENCE
   102→
   103→**File:** `apps/canvas/src/state/canvas-machine.ts`
   104→
   105→```typescript
   106→import { createMachine } from '@zazcart/tools';
   107→import { viewportSlice } from './viewport';
   108→import { interactionSlice } from './interaction';
   109→
   110→export const canvasMachine = createMachine({
   111→  id: 'canvas',
   112→  slices: {
   113→    viewport: viewportSlice,
   114→    interaction: interactionSlice,
   115→  },
   116→  context: {
   117→    userID: null,  // Canvas is public/anonymous
   118→  },
   119→  // Disable metadata tracking for high-frequency state updates (60fps)
   120→  metadata: false,
   121→});
   122→
   123→// Typed hooks for React components
   124→export const useCanvas = canvasMachine.useMachine;
   125→export const useCanvasSelector = canvasMachine.useSelector;
   126→
   127→// Actions for dispatching state changes
   128→export const canvasActions = canvasMachine.actions;
   129→
   130→// Direct store access for animation loops (no React re-render)
   131→export const canvasStore = {
   132→  getState: canvasMachine.getState,
   133→  dispatch: canvasMachine.dispatch,
   134→  subscribe: canvasMachine.subscribe,
   135→};
   136→```
