// Minimap dimensions
const MINIMAP_WIDTH = 200;
const MINIMAP_HEIGHT = 80;

// Uses d3-scale for coordinate conversion
function worldToMinimap(worldX, worldY, worldWidth, worldHeight) {
  const scaleX = scaleLinear().domain([0, worldWidth]).range([0, MINIMAP_WIDTH]);
  const scaleY = scaleLinear().domain([0, -worldHeight]).range([0, MINIMAP_HEIGHT]);
  return { x: scaleX(worldX), y: scaleY(worldY) };
}

// Heatmap grid (40x10 cells)
function generateHeatmapData(tasks, totalDays, trainCount, gridCols, gridRows) {
  const grid = Array(gridRows).fill(null).map(() => Array(gridCols).fill(0));

  for (const task of tasks) {
    const col = Math.floor(task.startDay / (totalDays / gridCols));
    const row = Math.floor(task.trainIndex / (trainCount / gridRows));
    grid[clampedRow][clampedCol]++;
  }

  return grid;
}
