    53→## 2. Core API
    54→
    55→The library uses a **slice-based state machine pattern** (NOT FSM/XState style). This is a critical distinction.
    56→
    57→### 2.1 createSlice / createSyncSlice
    58→
    59→Creates a synchronous state slice with Immer-powered reducers.
    60→
    61→```typescript
    62→import { createSlice, createSyncSlice } from '@belt/tools';
    63→// Note: createSlice and createSyncSlice are aliases
    64→
    65→interface ViewportState {
    66→  camera: { x: number; y: number };
    67→  zoom: number;
    68→  isPanning: boolean;
    69→}
    70→
    71→const viewportSlice = createSlice({
    72→  // Unique identifier for this slice
    73→  id: 'viewport',
    74→
    75→  // Initial state (fully typed)
    76→  initial: {
    77→    camera: { x: 0, y: 0 },
    78→    zoom: 1,
    79→    isPanning: false,
    80→  } satisfies ViewportState,
    81→
    82→  // Cache strategy for persistence
    83→  cache: {
    84→    policy: 'session',  // 'public' | 'private' | 'session'
    85→    ttl: '1h',          // Optional time-to-live
    86→    swr: true,          // Stale-while-revalidate
    87→  },
    88→
    89→  // Reducers (Immer draft - "mutable" syntax)
    90→  reducers: {
    91→    setCamera(state, payload: { x: number; y: number }) {
    92→      state.camera = payload;  // Direct mutation via Immer
    93→    },
    94→
    95→    setZoom(state, payload: number) {
    96→      state.zoom = payload;
    97→    },
    98→
    99→    startPan(state) {
   100→      state.isPanning = true;
   101→    },
   102→
   103→    endPan(state) {
   104→      state.isPanning = false;
   105→    },
   106→
   107→    // Can return new state instead of mutating
   108→    reset() {
   109→      return { camera: { x: 0, y: 0 }, zoom: 1, isPanning: false };
   110→    },
   111→  },
   112→});
   113→```
   114→
   115→**API Signature:**
   116→```typescript
   117→interface CreateSlice {
   118→  <State, Reducers, ID extends string>(
   119→    config: SliceConfig<State, Reducers, ID>
   120→  ): Slice<State, Reducers, ID>;
   121→}
   122→
   123→interface SliceConfig<State, Reducers, ID> {
   124→  id: ID;
   125→  initial: State;
   126→  reducers: Reducers;
   127→  cache: CacheStrategy;
   128→}
   129→```
