   329→## 4. React Integration
   330→
   331→### Hooks Available
   332→
   333→#### useSelector
   334→
   335→Subscribes to state changes using `useSyncExternalStore` for synchronous updates.
   336→
   337→```typescript
   338→// From machine
   339→const { useSelector } = canvasMachine;
   340→
   341→// In component
   342→function MyComponent() {
   343→  // Subscribe to specific state slice
   344→  const zoom = useSelector(state => state.viewport.zoom);
   345→  const camera = useSelector(state => state.viewport.camera);
   346→
   347→  // Derived values (computed on each render)
   348→  const lod = useSelector(state =>
   349→    state.viewport.zoom < 0.5 ? 'MACRO' :
   350→    state.viewport.zoom > 2.0 ? 'MICRO' : 'MESO'
   351→  );
   352→
   353→  return <div>Zoom: {zoom}</div>;
   354→}
