### Animation Loop Pattern

```typescript
// canvas/CameraController.tsx
import { useFrame } from '@react-three/fiber';
import { canvasStore, canvasActions } from '../state/canvas-machine';

export function CameraController() {
  useFrame(() => {
    // ALWAYS use getState() in animation loops
    const state = canvasStore.getState();
    const { animation, camera } = state.viewport;

    if (!animation.isAnimating) return;

    const elapsed = Date.now() - animation.startTime;
    const progress = Math.min(elapsed / animation.duration, 1);
    const eased = easeOutCubic(progress);

    const newCamera = {
      x: lerp(animation.startX, animation.targetX, eased),
      y: lerp(animation.startY, animation.targetY, eased),
    };

    canvasStore.dispatch(canvasActions.viewport.updateAnimation({ camera: newCamera }));

    if (progress >= 1) {
      canvasStore.dispatch(canvasActions.viewport.stopAnimation());
    }
  });

  return null;
}

function lerp(start: number, end: number, t: number): number {
  return start + (end - start) * t;
}

function easeOutCubic(t: number): number {
  return 1 - Math.pow(1 - t, 3);
}
```

