     1→/**
     2→ * MesoLayer - DNA-like task block visualization
     3→ *
     4→ * Renders task blocks using InstancedMesh for optimal performance.
     5→ * Visible at zoom levels 0.5x - 2.0x (MESO LOD level).
     6→ *
     7→ * Features:
     8→ * - InstancedMesh for all task blocks (single draw call)
     9→ * - Color coding: blue (maintenance), orange (overhaul), gray (inspection)
    10→ * - Conflict indicators: red border effect on hasConflict tasks
    11→ * - Alternating row backgrounds for readability
    12→ */
    13→
    14→import { useMemo, useRef, useEffect } from 'react';
    15→import { InstancedMesh, Object3D, Color, Matrix4 } from 'three';
    16→import type { TaskRender } from '../../data/types';
    17→import { DEFAULT_VIEW_CONFIG } from '../../data/types';
    18→import type { ISpatialIndex, ViewportBounds } from '../../spatial';
    19→
    20→interface MesoLayerProps {
    21→  tasks: TaskRender[];
    22→  trainCount: number;
    23→  /** Opacity for LOD transitions (0-1). Default: 1 */
    24→  opacity?: number;
    25→  /** Viewport bounds for culling (PERF-002) */
    26→  viewportBounds?: ViewportBounds;
    27→  /** Spatial index for efficient viewport queries (PERF-002) */
    28→  spatialIndex?: ISpatialIndex;
    29→  /** Currently hovered task ID for highlight effect */
    30→  hoveredTaskId?: string | null;
    31→  /** Currently selected task ID for selection highlight (F019) */
    32→  selectedTaskId?: string | null;
    33→  /** Currently keyboard-focused task ID for focus indicator (F021) */
    34→  focusedTaskId?: string | null;
    35→}
    36→
    37→// Color palette matching POC reference
    38→const COLORS: Record<string, string> = {
    39→  blue: '#3b82f6',    // maintenance
    40→  orange: '#f59e0b',  // overhaul
    41→  gray: '#9ca3af',    // inspection
    42→};
    43→
    44→const CONFLICT_COLOR = '#ef4444'; // red for conflicts
    45→
    46→// Row background colors (alternating)
    47→const ROW_BG_EVEN = '#ffffff';
    48→const ROW_BG_ODD = '#f8fafc';
    49→
    50→const { pxPerDay, pxPerTrain } = DEFAULT_VIEW_CONFIG;
    51→
    52→// Task block height (with padding)
    53→const TASK_HEIGHT = pxPerTrain - 4; // 20px height with 2px padding top/bottom
    54→const TASK_PADDING_Y = 2;
    55→
    56→/**
    57→ * Renders alternating row backgrounds for train rows using InstancedMesh
    58→ * OPTIMIZED: Single draw call instead of 50 individual meshes
    59→ */
    60→function RowBackgrounds({
    61→  trainCount,
    62→  totalDays,
    63→  opacity = 1,
    64→}: {
    65→  trainCount: number;
    66→  totalDays: number;
    67→  opacity?: number;
    68→}) {
    69→  const totalWidth = totalDays * pxPerDay;
    70→  const meshRef = useRef<InstancedMesh>(null);
    71→  const tempObject = useMemo(() => new Object3D(), []);
    72→
    73→  useEffect(() => {
    74→    if (!meshRef.current || trainCount === 0) return;
    75→
    76→    const mesh = meshRef.current;
    77→
    78→    for (let i = 0; i < trainCount; i++) {
    79→      tempObject.position.set(
    80→        totalWidth / 2, // Center the row
    81→        -i * pxPerTrain - pxPerTrain / 2, // Y position (negative = down)
    82→        -0.1 // Behind tasks
    83→      );
    84→      tempObject.scale.set(totalWidth, pxPerTrain, 1);
    85→      tempObject.updateMatrix();
    86→      mesh.setMatrixAt(i, tempObject.matrix);
    87→      mesh.setColorAt(i, new Color(i % 2 === 0 ? ROW_BG_EVEN : ROW_BG_ODD));
    88→    }
    89→
    90→    mesh.instanceMatrix.needsUpdate = true;
    91→    if (mesh.instanceColor) {
    92→      mesh.instanceColor.needsUpdate = true;
    93→    }
    94→  }, [trainCount, totalWidth, tempObject]);
    95→
    96→  if (trainCount === 0) return null;
    97→
    98→  return (
    99→    <instancedMesh ref={meshRef} args={[undefined, undefined, trainCount]}>
   100→      <planeGeometry args={[1, 1]} />
   101→      <meshBasicMaterial transparent opacity={0.5 * opacity} />
   102→    </instancedMesh>
   103→  );
   104→}
   105→
   106→// Highlight color multiplier for hovered tasks
   107→// Using high value for clear visual feedback
   108→const HOVER_BRIGHTNESS = 1.8;
   109→
   110→// Selection indicator color (distinct cyan/teal)
   111→const SELECTION_COLOR = '#06b6d4'; // cyan-500
   112→
   113→// Focus indicator color (F021 - keyboard focus)
   114→// Using a distinct purple for focus to differentiate from selection
   115→const FOCUS_COLOR = '#8b5cf6'; // violet-500
   116→
   117→/**
   118→ * Brighten a color for hover effect
   119→ */
   120→function brightenColor(hexColor: string, factor: number): Color {
   121→  const color = new Color(hexColor);
   122→  color.r = Math.min(1, color.r * factor);
   123→  color.g = Math.min(1, color.g * factor);
   124→  color.b = Math.min(1, color.b * factor);
   125→  return color;
   126→}
   127→
   128→/**
   129→ * Main task blocks using InstancedMesh
   130→ */
   131→function TaskBlocks({
   132→  tasks,
   133→  opacity = 1,
   134→  hoveredTaskId,
   135→  selectedTaskId,
   136→  focusedTaskId,
   137→}: {
   138→  tasks: TaskRender[];
   139→  opacity?: number;
   140→  hoveredTaskId?: string | null;
   141→  selectedTaskId?: string | null;
   142→  focusedTaskId?: string | null;
   143→}) {
   144→  const meshRef = useRef<InstancedMesh>(null);
   145→  const tempObject = useMemo(() => new Object3D(), []);
   146→  const tempColor = useMemo(() => new Color(), []);
   147→
   148→  // Update instance matrices and colors when tasks change or hover/selection/focus changes
   149→  useEffect(() => {
   150→    if (!meshRef.current) return;
   151→
   152→    const mesh = meshRef.current;
   153→
   154→    tasks.forEach((task, i) => {
   155→      // Calculate position and size
   156→      const width = task.duration * pxPerDay;
   157→      const height = TASK_HEIGHT;
   158→      const x = task.startDay * pxPerDay + width / 2; // Center of task
   159→      const y = -task.trainIndex * pxPerTrain - pxPerTrain / 2; // Negative Y (down)
   160→      // Z ordering: selected > focused > conflict > hovered > normal
   161→      const isSelected = task.id === selectedTaskId;
   162→      const isFocused = task.id === focusedTaskId;
   163→      const isHovered = task.id === hoveredTaskId;
   164→      const z = isSelected ? 0.2 : isFocused ? 0.15 : task.hasConflict ? 0.1 : isHovered ? 0.05 : 0;
   165→
   166→      // Set transform
   167→      tempObject.position.set(x, y, z);
   168→      tempObject.scale.set(width, height, 1);
   169→      tempObject.updateMatrix();
   170→      mesh.setMatrixAt(i, tempObject.matrix);
   171→
   172→      // Set color: selected gets distinct color, focused gets focus color, hovered gets brightened, normal is base
   173→      if (isSelected) {
   174→        tempColor.set(SELECTION_COLOR);
   175→        mesh.setColorAt(i, tempColor);
   176→      } else if (isFocused) {
   177→        // Focus uses a distinct purple color to differentiate from selection and hover
   178→        tempColor.set(FOCUS_COLOR);
   179→        mesh.setColorAt(i, tempColor);
   180→      } else if (isHovered) {
   181→        const baseColor = task.hasConflict ? CONFLICT_COLOR : COLORS[task.color];
