/**
 * MacroLayer - Strategic heatmap visualization
 *
 * Renders a heatmap showing task density across trains and time.
 * Visible at zoom levels < 0.5x (MACRO LOD level).
 *
 * Features:
 * - Aggregates tasks by month/train into cells
 * - Color gradient: yellow (low) → orange (medium) → red (high density)
 * - InstancedMesh for optimal performance
 * - Shows 10-20 year strategic overview
 *
 * D3-MIGRATE-001: Uses d3-scale-chromatic for heatmap color interpolation
 */

import { useMemo, useRef, useEffect } from 'react';
import { InstancedMesh, Object3D, Color } from 'three';
import { interpolateYlOrRd } from 'd3-scale-chromatic';
import type { TaskRender } from '../../data/types';
import { DEFAULT_VIEW_CONFIG } from '../../data/types';

interface MacroLayerProps {
  tasks: TaskRender[];
  trainCount: number;
  totalYears?: number;
  /** Opacity for LOD transitions (0-1). Default: 1 */
  opacity?: number;
}

const { pxPerDay, pxPerTrain } = DEFAULT_VIEW_CONFIG;

// Heatmap cell size
const DAYS_PER_CELL = 30; // ~1 month per cell
const CELL_WIDTH = DAYS_PER_CELL * pxPerDay; // 300px
const CELL_HEIGHT = pxPerTrain; // 24px per train row
const CELL_GAP = 1; // Small gap between cells

// Empty cell background color
const EMPTY_CELL_COLOR = '#f8fafc'; // slate-50

/**
 * Interpolate between colors based on density (0-1)
 * D3-MIGRATE-001: Uses d3-scale-chromatic interpolateYlOrRd for heatmap colors
 *
 * The YlOrRd (Yellow-Orange-Red) scale is a standard sequential color scheme
 * designed for heatmaps, providing perceptually uniform color progression.
 */
function getHeatmapColor(density: number): Color {
  // No tasks = light background
  if (density === 0) {
    return new Color(EMPTY_CELL_COLOR);
  }

  // Normalize density (0-1 range, with max around 8 tasks)
  const normalizedDensity = Math.min(density / 8, 1);

  // Use d3 YlOrRd scale (0 = yellow, 1 = red)
  // Start at 0.1 to avoid very light yellow for low values
  const t = 0.1 + normalizedDensity * 0.9;
  const colorString = interpolateYlOrRd(t);

  return new Color(colorString);
}

/**
 * Calculate task density per cell
 * Returns a 2D array: [trainIndex][monthIndex] = task count
 */
function calculateDensityGrid(
  tasks: TaskRender[],
  trainCount: number,
  totalMonths: number
): number[][] {
  // Initialize grid with zeros
  const grid: number[][] = Array.from({ length: trainCount }, () =>
    Array(totalMonths).fill(0)
  );

  // Count tasks in each cell
  for (const task of tasks) {
    // Calculate which month(s) this task spans
    const startMonth = Math.floor(task.startDay / DAYS_PER_CELL);
    const endMonth = Math.floor((task.startDay + task.duration) / DAYS_PER_CELL);

    // Increment count for all months the task spans
    for (let month = startMonth; month <= endMonth && month < totalMonths; month++) {
      if (month >= 0 && task.trainIndex >= 0 && task.trainIndex < trainCount) {
        grid[task.trainIndex][month]++;
      }
    }
  }

  return grid;
}

/**
 * MacroLayer Component
 *
 * Renders the strategic heatmap visualization for the MACRO LOD level.
 */
export function MacroLayer({ tasks, trainCount, totalYears = 10, opacity = 1 }: MacroLayerProps) {
  const meshRef = useRef<InstancedMesh>(null);
  const tempObject = useMemo(() => new Object3D(), []);

  // Calculate grid dimensions
  const totalMonths = totalYears * 12;
  const totalCells = trainCount * totalMonths;

  // Calculate density grid
  const densityGrid = useMemo(
    () => calculateDensityGrid(tasks, trainCount, totalMonths),
    [tasks, trainCount, totalMonths]
  );

  // Update instance matrices and colors
  useEffect(() => {
    if (!meshRef.current) return;

    const mesh = meshRef.current;

    let instanceIndex = 0;

    for (let trainIndex = 0; trainIndex < trainCount; trainIndex++) {
      for (let monthIndex = 0; monthIndex < totalMonths; monthIndex++) {
        // Calculate position
        const x = monthIndex * CELL_WIDTH + CELL_WIDTH / 2;
        const y = -trainIndex * CELL_HEIGHT - CELL_HEIGHT / 2;
        const z = 0;

        // Set transform
        tempObject.position.set(x, y, z);
        tempObject.scale.set(CELL_WIDTH - CELL_GAP, CELL_HEIGHT - CELL_GAP, 1);
        tempObject.updateMatrix();
        mesh.setMatrixAt(instanceIndex, tempObject.matrix);

        // Set color based on density
        const density = densityGrid[trainIndex]?.[monthIndex] ?? 0;
        const color = getHeatmapColor(density);
        mesh.setColorAt(instanceIndex, color);

        instanceIndex++;
      }
    }

    // Mark buffers for update
    mesh.instanceMatrix.needsUpdate = true;
    if (mesh.instanceColor) {
      mesh.instanceColor.needsUpdate = true;
    }
  }, [densityGrid, trainCount, totalMonths, tempObject]);

  if (totalCells === 0) {
    return null;
  }

  return (
    <group>
      {/* Heatmap cells */}
      <instancedMesh
        ref={meshRef}
        args={[undefined, undefined, totalCells]}
      >
        <planeGeometry args={[1, 1]} />
        <meshBasicMaterial
          toneMapped={false}
          transparent={opacity < 1}
          opacity={opacity}
        />
      </instancedMesh>

      {/* Year markers (vertical lines) */}
      <YearMarkers totalYears={totalYears} trainCount={trainCount} opacity={opacity} />
    </group>
  );
}

/**
 * Renders vertical lines for year boundaries
 */
function YearMarkers({
  totalYears,
  trainCount,
  opacity = 1,
}: {
  totalYears: number;
  trainCount: number;
  opacity?: number;
}) {
  const totalHeight = trainCount * CELL_HEIGHT;
  const markerColor = '#94a3b8'; // slate-400

  return (
    <group>
      {Array.from({ length: totalYears + 1 }, (_, year) => {
        const x = year * 12 * CELL_WIDTH;
        return (
          <mesh key={`year-${year}`} position={[x, -totalHeight / 2, 0.05]}>
            <planeGeometry args={[2, totalHeight]} />
            <meshBasicMaterial color={markerColor} transparent opacity={0.3 * opacity} />
          </mesh>
        );
      })}
    </group>
  );
}
